import threading
import time

class DataCache:
    _instance = None
    _cache = {}
    _lock = threading.Lock()

    @classmethod
    def get_instance(cls):
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    def store(self, key, data):
